mapper.insert:
/*
  QueryID : com.kdt.mapper.interview.insertApplyInterview
  Description : 클라이언트의 면담 요청을 받아 TB_INTERVIEW에 insert
  작성자 : 김동식
  */
INSERT INTO TB_INTERVIEW (
    ITV_APLCNT_SN,
    ITV_APLY_TTL, ITV_APLY_CN, COHORT_SN, FORM_UUID, ITV_PIC_AUTHRT, ITV_APLY_DT, CO_SN
) VALUES (
             #{itvAplcntSn},
             #{title}, #{content}, #{cohortSn}, #{formUuid}, #{itvPicAuthrt}, #{itvAplyDt}, #{coSn}
         )

mapper.select:
/* QueryID : com.kdt.mapper.interview.getMyInterviewRequests Description : 회사내 모든 기수의 배정되지 않은 면담을 보여준다. (가장 오래된 신청부터) Author: 구서영 Rule: - 대표(2): ITV_PIC_AUTHRT = 2 - 직원(3): ITV_PIC_AUTHRT = 3 - 강사(4): ITV_PIC_AUTHRT = 4 - 공통: COHORT_SN = cohortSn -> 여기 샵 괄호 이런거 쓰면 에러뜸 사용 ㄴㄴ */ SELECT i.ITV_SN AS itvSn, i.COHORT_SN AS cohortSn, i.ITV_APLY_TTL AS itvAplyTtl, i.ITV_APLY_CN AS itvAplyCn, i.ITV_CFMTN_DT as itvCfmtnDt, i.ITV_APLY_DT AS itvAplyDt, i.ITV_PIC_AUTHRT AS itvPicAutht, i.ITV_PIC_SN AS itvPicSn, i.ITV_APLCNT_SN AS itvAplcntSn, i.ITV_PRNMNT_DT AS itvPrnmntDt, u1.USER_NM AS itvAplcntNm, -- 신청자 명 u2.USER_NM AS itvPicNm, -- 담당자 명 i.ITV_PLC AS itvPlc, i.PIC_CAL_SN AS picCalSn, i.APLCNT_CAL_SN AS aplcntCalSn, i.VIEW_CNT AS viewCnt, -- 조회수 CASE WHEN i.ITV_PRNMNT_DT IS NULL THEN '면담신청' ELSE '면담확정' END AS postType FROM TB_INTERVIEW i JOIN TB_COHORT c ON c.COHORT_SN = i.COHORT_SN JOIN TB_USER u1 ON u1.USER_SN = i.ITV_APLCNT_SN -- 이름 매칭용 LEFT JOIN TB_USER u2 ON u2.USER_SN = i.ITV_PIC_SN -- 이름 매칭용 WHERE 1=1
AND c.CO_SN = #{coSn}
AND i.DEL_YN = 0
AND i.COHORT_SN = #{cohortSn}
AND i.ITV_APLCNT_SN = #{userSn}
AND i.ITV_PIC_AUTHRT = #{roleType} AND i.ITV_PRNMNT_DT IS NULL
ORDER BY i.ITV_APLY_DT ASC
